UPDATE public.questions SET
  stimulus_text = 'The word ''whose'' is a relative pronoun, which means it connects a dependent clause to a noun or pronoun in the main clause. But it can only be used in certain situations. For example, the word ''whose'' can only be used to refer to a noun that is "the possessor of something." This means that the word ''whose'' can be used to describe a noun that owns or possesses something else, but it cannot be used to describe a noun that is simply related to something else.',
  question_text = 'Which of the following sentences correctly uses the relative pronoun ''whose''?',
  stimulus_type = NULL,
  options = '[{"id":"A","text":"The woman, whose dress was torn, asked for help.","is_correct":false,"explanation":"Choice A is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"The dog, whose tail was wagging, ran towards its owner.","is_correct":true,"explanation":"Choice B matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"The city, whose history is fascinating, is full of old buildings.","is_correct":false,"explanation":"Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"The car, whose engine was broken, needed to be towed.","is_correct":false,"explanation":"Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'B',
  explanation = 'The sentence "The dog, whose tail was wagging, ran towards its owner." correctly uses the relative pronoun "whose." The word "whose" is used to refer to the dog, which "possesses" its tail. The other sentences use "whose" incorrectly because they are used to refer to something that is simply related to the noun, not the possessor of the noun. For example, in sentence A, the woman does not "possess" her dress; in sentence C, the city does not "possess" its history; and in sentence D, the car does not "possess" its engine. The passage states that "The word ''whose'' is a relative pronoun, which means it connects a dependent clause to a noun or pronoun in the main clau…", which is the textual anchor for eliminating weaker choices. Choice B is correct because it aligns with that evidence: The dog, whose tail was wagging, ran towards its owner.. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
